  ('disabled-57f41407-moex-00576', 'disabled-57f41407', 'disabled-57f41407-moex-111-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '行政處分之利害關係人若欲提起訴願，關於期限之敘述，下列何者正確？', '["其救濟期間一律以行政處分送達時起算", "自行政處分公告期滿後，已逾3年者，不得提起訴願", "訴願之提起，以行政處分公告期滿之次日起30日內", "利害關係人提起訴願之期間並無特別規定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "6dac6e4ea24d", "answer_pdf_sha1": "6ce7edc90a97", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0312", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00577', 'disabled-57f41407', 'disabled-57f41407-moex-111-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '下列關於民事訴訟中當事人適格及選定當事人之敘述，何者正確？', '["多數有共同利益之人，不合於非法人團體者，僅得由其中選定一人，由 該人為被選定人全體起訴，但不得被訴", "多數有共同利益之人為同一公益社團法人之社員者，於章程所定目的範 圍內，得選定該法人為選定人起訴", "訴訟繫屬後，並經選定當事人者，該被選定人脫離訴訟", "被選定人有為選定人為一切訴訟行為之權，但除特別授權外，不包括捨 棄、認諾、撤回或和解"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "6dac6e4ea24d", "answer_pdf_sha1": "6ce7edc90a97", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0312", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00578', 'disabled-57f41407', 'disabled-57f41407-moex-111-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '甲委任乙律師為訴訟代理人，向丙提起民事訴訟。下列何者非屬訴訟代理 權消滅事由？', '["甲死亡", "乙死亡", "乙受監護宣告", "甲終止對乙之訴訟委任，並已將此一情事通知丙"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "6dac6e4ea24d", "answer_pdf_sha1": "6ce7edc90a97", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0312", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00579', 'disabled-57f41407', 'disabled-57f41407-moex-111-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '下列何類型之民事訴訟事件，最可能上訴至最高法院？', '["因搭乘火車出軌，致親人死亡者，請求賠償", "A、B機車發生輕微擦撞，A機車受損時，請求賠償", "甲1人在住宿的飯店餐廳用餐，因食物中毒，請求賠償", "開租來的高級名車自撞護欄時，出租人請求賠償車損"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "6dac6e4ea24d", "answer_pdf_sha1": "6ce7edc90a97", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0312", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00580', 'disabled-57f41407', 'disabled-57f41407-moex-111-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '甲市政府環保局之垃圾車沿路收集垃圾，轉彎時不慎撞上機車騎士乙，致 乙機車損壞及身體受傷時，乙對甲提起國家賠償訴訟，應適用下列何種程 序法之規定？', '["刑事訴訟法", "行政訴訟法", "民事訴訟法", "非訟事件法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "6dac6e4ea24d", "answer_pdf_sha1": "6ce7edc90a97", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0312", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00581', 'disabled-57f41407', 'disabled-57f41407-moex-111-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', 'A地上有定著B屋一棟、百年桂花樹2株，尚有遊客臨時搭建固定於A地 之旅遊帳篷3座，上述共有多少件動產及不動產？', '["1件不動產與3件動產", "2件不動產與3件動產", "2件不動產與5件動產", "4件不動產與3件動產"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "6dac6e4ea24d", "answer_pdf_sha1": "6ce7edc90a97", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0312", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00582', 'disabled-57f41407', 'disabled-57f41407-moex-111-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '甲出售一輛跑車於乙，約定價金新臺幣 500 萬元，分 10 期給付，雙方並 約定甲先交付該車於乙，乙於給付完各期價金後，始取得該車所有權。下 列敘述何者正確？', '["甲乙間之買賣契約附有停止條件", "乙在給付各期價金前，得讓與其期待權於他人", "如乙給付第4期價金後即未再給付價金，甲得自行到乙宅取回該車", "乙給付全部價金前駕駛該車出遊，遭丙駕車超速衝撞以致該車全毀，僅 甲得以其所有權受侵害為由，依侵權行為規定，得向丙請求損害賠償"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "6dac6e4ea24d", "answer_pdf_sha1": "6ce7edc90a97", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0312", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00583', 'disabled-57f41407', 'disabled-57f41407-moex-111-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '甲對乙一見鍾情，遂與乙約定將甲所有之A畫無償贈與乙，乙欣然接受。 下列敘述何者錯誤？', '["因贈與為不要物契約，甲為贈與之意思表示，而乙允受，故成立A畫之 贈與契約", "A畫之權利未移轉前，甲得任意撤銷其贈與", "若A畫之贈與契約經過公證，則甲不得任意撤銷其贈與", "乙故意侵害甲之配偶丙而致重傷。甲得知乙之罪行後，欲撤銷該贈與契 約。但因該契約經過公證並已交付，故無法撤銷贈與"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "6dac6e4ea24d", "answer_pdf_sha1": "6ce7edc90a97", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0312", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00584', 'disabled-57f41407', 'disabled-57f41407-moex-111-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '甲有 A 屋出租於乙，乙未經甲之承諾，竟將 A 屋全部轉租於丙。下列敘 述何者正確？', '["乙依法有權將A屋全部轉租於丙", "乙與丙間關於A屋轉租契約有效", "甲得終止乙與丙訂立之轉租契約", "甲得請求丙給付租金"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "6dac6e4ea24d", "answer_pdf_sha1": "6ce7edc90a97", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0312", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00585', 'disabled-57f41407', 'disabled-57f41407-moex-111-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '所有權乃私有財產制之核心。下列關於所有權內容之敘述，何者錯誤？', '["所有權之內容，包括所有物之占有", "所有權之內容，包括所有物之使用收益", "所有權之內容，包括所有物之處分", "所有權之內容，包括負擔交付標的物之給付義務"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "6dac6e4ea24d", "answer_pdf_sha1": "6ce7edc90a97", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0312", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL)
